using System.ComponentModel;
using System.Drawing;
using System.Runtime.InteropServices;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // In .NET 9 the default StatusStrip renderer changed. Explicitly set the
        // system renderer to preserve .NET 8 visual behavior.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }

    [Browsable(true)]
    public string DisplayName { get; set; }

    [Browsable(true)]
    public int MaxItems { get; set; }
}

// Demonstrates the fix for IWindowsFormsEditorService.DropDownControl(null)
// which now throws ArgumentNullException in .NET 9.
public class SafeDropDownEditor
{
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        // In .NET 9, passing null to DropDownControl throws ArgumentNullException.
        // Guard against null before calling.
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }
    }
}

